import{_ as a,o as t,c as n,j as r,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const I=JSON.parse('{"title":"17、星星【XVII】","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/17、星星【XVII】.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/17、星星【XVII】.md"}'),o={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/17、星星【XVII】.md"};function d(_,e,b,i,l,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"_17、星星【xvii】",tabindex:"-1"},[p("17、星星【XVII】 "),r("a",{class:"header-anchor",href:"#_17、星星【xvii】","aria-label":'Permalink to "17、星星【XVII】"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002")])])],-1),s('<h1 id="星星" tabindex="-1">星星 <a class="header-anchor" href="#星星" aria-label="Permalink to &quot;星星&quot;">​</a></h1><p>白金之星</p><p>SSS+27200<br> 替身外貌：<br> 主体为蓝紫色，外观为留着长发的壮硕男性。</p><p>替身数据：<br> 破坏力A<br> 速度A（偏斜防御）<br> 射程C<br> 持续力A<br> 精密动作性A<br> 成长性A</p><p>替身对应主属性：决心</p><p>替身能力：<br> 近距离力量型：近距离力量型都具有的基础能力，控制替身直接对目标进行肉搏攻击，检定方式为【决心—专注—主专业：替身使用—副专业：精神力（专注下属副专业）】。</p><p>オラオラ：由于白金之星的破坏力与速度都达到了A，因此在进行肉搏攻击时可以连打，消耗一个标准动作对目标快速攻击四次。并且可作为一种应对技，每轮4次，不以防御对抗对方的伤害数，而是进行一次普通攻击，以攻击伤害数抵消对方，与其它应对技一样需要反射动作调用，这是一个SSS级时空来源的无敌效果。</p><p>白金之星·世界：白金之星具有对时间效果的抗性与免疫力，视为SS级时空来源免疫。当遇到S级及以上的时间停止能力时，免疫后将会解锁令时间停止的替身能力。<br> 动作：迅捷<br> 范围：特殊<br> 成分：言语<br> 目标：场景内除自身外的所有单位<br> 效果：<br> 使用本能力后的下一行动轮开始时，人物率先进行一个特殊的回合，但不会因进入此回合获得AP点数（无论是基础还是额外的），取而代之的是人物可以将自身回合可使用的至多4点AP分配至此回合内。人物的耐力与决心属性上每合计有1个附加成功，可分配给此特殊回合的AP值就增加1点。<br> 受影响单位在应对人物在这一特殊回合内进行的任何行为时都处于SS级时空来源的时间停止状态。<br> 若有单位免疫此能力的影响，则其也会如同你一般获得特殊回合。在判定执行此特殊回合的先后顺序时，以先攻顺位为准。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const S=a(o,[["render",d]]);export{I as __pageData,S as default};
